from enum import Enum
from typing import Optional

class Operation(Enum):
    ADD = 'add'
    SUBTRACT = 'sub'
    MULTIPLY = 'mul'
    DIVIDE = 'div'

def calculate(a: float, b: float, operation: Operation) -> Optional[float]:
    """Perform a basic arithmetic operation on two numbers."""
    operations = {
        Operation.ADD: lambda: a + b,
        Operation.SUBTRACT: lambda: a - b,
        Operation.MULTIPLY: lambda: a * b,
        Operation.DIVIDE: lambda: a / b if b != 0 else None,
    }
    return operations.get(operation, lambda: None)()

